		if sessionPath == "" {
			resolved, err := ResolveSessionPath(ref.SessionDir, ref.SessionID, ref.Cwd)
			if err != nil {
				return "", ctx, err
			}
			sessionPath = resolved
		}
		text, err := ExtractFinalAssistantTextFromSession(sessionPath)
		if err != nil {
